// ponytail: mirrors OJ-DFY-Onboarding's Stripe-webhook-parse + idempotency-by-session_id shape,
// extended to be tier-aware for BOTH the EUR1,000 BS assessment purchase and the EUR25,000 BS DFY
// purchase (different onboarding content each), distinct from BS-Stripe-Payment-Delivery (which
// handles report delivery, not the welcome/kickoff email, and has no idempotency guard).
// pod task-runner disallows require('https'); use n8n helpers.httpRequest instead
async function hGet(h,p,hdr){
  const resp = await this.helpers.httpRequest({ method: 'GET', url: 'https://' + h + p, headers: hdr, json: true });
  return resp;
}

const SK = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InNyaHBtdmZkemxsc292bHVhaGpmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MTgzMjE1MSwiZXhwIjoyMDk3NDA4MTUxfQ.zlZs4caHZQSgSs5OIHYnXP_8RaJlpoNH2mA_U76qsMA";
const SH = { apikey: SK, Authorization: 'Bearer '+SK };

const raw = $input.first().json;
const body = raw.body || raw;
const eventType = body.type || 'checkout.session.completed'; // default so a raw test-session payload (no envelope) still works
const dataObj = (body.data && body.data.object) ? body.data.object : body;

if (eventType !== 'checkout.session.completed') {
  return [{ json: { skipped: true, reason: 'not_a_checkout_completion', event_type: eventType } }];
}

const customerEmail = (dataObj.customer_email || (dataObj.customer_details && dataObj.customer_details.email) || '').toLowerCase();
const sessionId = dataObj.id || null;
const amountTotal = (dataObj.amount_total || 0) / 100;
const livemode = body.livemode === true;

if (!sessionId) {
  return [{ json: { skipped: true, reason: 'no_session_id' } }];
}

// Idempotency: skip if this session_id was already onboarded (bs_event_log, action_type=bs_onboarding_sent).
const seen = await hGet.call(this, 'srhpmvfdzllsovluahjf.supabase.co', '/rest/v1/bs_event_log?action_type=eq.bs_onboarding_sent&task_id=eq.' + encodeURIComponent(sessionId) + '&select=id&limit=1', SH);
if (Array.isArray(seen) && seen.length > 0) {
  return [{ json: { skipped: true, reason: 'already_onboarded', session_id: sessionId } }];
}

// Tier detection: metadata.tier wins if set, else infer from amount (EUR1,000 assessment vs EUR25,000 DFY).
let tier = (dataObj.metadata && dataObj.metadata.tier) ? dataObj.metadata.tier : null;
if (!tier) {
  tier = amountTotal >= 10000 ? 'dfy' : 'assessment';
}

// Best-effort contact match by email (BS contacts table, not 'prospects' -- that's the OJ tenant's table name).
let firstName = 'there', company = 'your organization';
if (customerEmail) {
  const rows = await hGet.call(this, 'srhpmvfdzllsovluahjf.supabase.co', '/rest/v1/contacts?email=eq.' + encodeURIComponent(customerEmail) + '&select=name,company&limit=1', SH);
  if (Array.isArray(rows) && rows.length > 0) {
    firstName = (rows[0].name || '').split(' ')[0] || firstName;
    company = rows[0].company || company;
  }
}

const TO = customerEmail || 'info+bsonboard-test@bettersocieties.world';

return [{ json: { ok: true, tier, sessionId, amountTotal, livemode, customerEmail: TO, firstName, company } }];

const SB_URL = 'https://srhpmvfdzllsovluahjf.supabase.co/rest/v1';
const SB_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InNyaHBtdmZkemxsc292bHVhaGpmIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MTgzMjE1MSwiZXhwIjoyMDk3NDA4MTUxfQ.zlZs4caHZQSgSs5OIHYnXP_8RaJlpoNH2mA_U76qsMA';

// ponytail: the Gmail node's output REPLACES $json with its own response shape (id/threadId/labelIds),
// dropping the custom fields set upstream -- read the purchase context from the named upstream node
// instead of $input.item.json, which now holds only the Gmail response.
const p = $('Build Tier-Aware Onboarding Email').item.json;
const gmailResp = $input.item.json; // Gmail node output includes id/threadId on success

let logResult = { ok: false };
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: SB_URL + '/bs_event_log',
    headers: { apikey: SB_KEY, Authorization: 'Bearer ' + SB_KEY, 'Content-Type': 'application/json', Prefer: 'return=representation' },
    body: {
      action_type: 'bs_onboarding_sent',
      task_id: p.sessionId,
      summary: 'BS onboarding email sent (' + p.tier + ' tier)',
      payload: { tier: p.tier, to: p.customerEmail, amount_eur: p.amountTotal, gmail_message_id: gmailResp.id || null, session_id: p.sessionId },
      is_test: !p.livemode,
      livemode: !!p.livemode,
    },
    json: true,
  });
  logResult = { ok: true, log_id: resp && resp[0] && resp[0].id };
} catch (e) {
  logResult = { ok: false, error: String(e) };
}

return [{ json: { onboarding_sent: true, tier: p.tier, to: p.customerEmail, session_id: p.sessionId, gmail_message_id: gmailResp.id || null, log: logResult } }];
